code = """import json, re, pandas as pd

biz_records = var_call_W3wtdSJsZlYqst59cO1WtLwz

biz_df = pd.DataFrame(biz_records)

states = []
for desc in biz_df['description']:
    m = re.search(r', ([A-Z]{2})[, ]', desc)
    states.append(m.group(1) if m else None)

biz_df['state'] = states
biz_df = biz_df.dropna(subset=['state'])

biz_df['business_ref'] = biz_df['business_id'].str.replace('businessid_', 'businessref_', regex=False)

import os
with open(var_call_OsI6EnhAISUWy1Q5XQKe8ptZ, 'r') as f:
    review_records = json.load(f)

rev_df = pd.DataFrame(review_records)
rev_df['rating'] = rev_df['rating'].astype(float)

merged = pd.merge(biz_df[['business_ref','state']], rev_df, on='business_ref', how='left')

state_counts = biz_df.groupby('state').size().rename('wifi_business_count')
state_avg_rating = merged.groupby('state')['rating'].mean()

summary = pd.concat([state_counts, state_avg_rating], axis=1).reset_index()
summary = summary.sort_values('wifi_business_count', ascending=False)

best = summary.iloc[0]

result = {
    'state_with_most_wifi_businesses': best['state'],
    'wifi_business_count': int(best['wifi_business_count']),
    'average_rating_for_wifi_businesses_in_state': None if pd.isna(best['rating']) else float(round(best['rating'],3))
}

out = json.dumps(result)
print("__RESULT__:")
print(out)"""

